import { VercelRequest, VercelResponse } from '@vercel/node';
import { sql } from '@vercel/postgres';

// Helper to check admin secret
const checkAdmin = (req: VercelRequest) => {
  const authHeader = req.headers['x-admin-secret'];
  return authHeader === process.env.ADMIN_SECRET_KEY;
};

export default async function handler(req: VercelRequest, res: VercelResponse) {
  if (!checkAdmin(req)) {
    return res.status(401).json({ error: 'Unauthorized' });
  }

  try {
    // 1. GET: List users
    if (req.method === 'GET') {
      const { rows } = await sql`SELECT * FROM users ORDER BY id DESC`;
      return res.status(200).json({ users: rows });
    }

    // 2. POST: Add user
    if (req.method === 'POST') {
      const { key, tier, limit } = req.body;
      await sql`
        INSERT INTO users (client_api_key, tier, daily_limit, usage_count)
        VALUES (${key}, ${tier}, ${limit}, 0)
      `;
      return res.status(200).json({ success: true });
    }

    // 3. DELETE: Remove user
    if (req.method === 'DELETE') {
      const { id } = req.query;
      await sql`DELETE FROM users WHERE id = ${id}`;
      return res.status(200).json({ success: true });
    }

    return res.status(405).json({ error: 'Method not allowed' });

  } catch (error: any) {
    console.error(error);
    return res.status(500).json({ error: 'Database error: ' + error.message });
  }
}
```

## api/user/verify.ts

**New File** (replaces `api/user/verify/route.ts`). This lets the frontend check if a key is valid.

```typescript
import { VercelRequest, VercelResponse } from '@vercel/node';
import { sql } from '@vercel/postgres';

export default async function handler(req: VercelRequest, res: VercelResponse) {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method not allowed' });
  }

  try {
    const { clientKey } = req.body;

    if (!clientKey) {
      return res.status(400).json({ valid: false, error: 'Key required' });
    }

    const { rows } = await sql`SELECT * FROM users WHERE client_api_key = ${clientKey} LIMIT 1`;

    if (rows.length === 0) {
      return res.status(403).json({ valid: false, error: 'Invalid Key' });
    }

    const user = rows[0];

    // Check for daily reset needed for accurate display
    const now = new Date();
    const today = now.toISOString().split('T')[0];
    const lastReset = user.last_reset_date ? new Date(user.last_reset_date).toISOString().split('T')[0] : null;

    let currentUsage = user.usage_count;
    if (lastReset !== today) {
        currentUsage = 0;
    }

    return res.status(200).json({
      valid: true,
      tier: user.tier,
      limit: user.daily_limit,
      usage: currentUsage,
      remaining: Math.max(0, user.daily_limit - currentUsage)
    });

  } catch (error: any) {
    return res.status(500).json({ valid: false, error: 'Server error: ' + error.message });
  }
}
```

## api/ai/generate.ts

**New File** (replaces `api/ai/generate/route.ts`). This is the proxy for Gemini.

```typescript
import { VercelRequest, VercelResponse } from '@vercel/node';
import { sql } from '@vercel/postgres';
import { GoogleGenAI } from '@google/genai';

// Initialize Gemini with server-side key
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export default async function handler(req: VercelRequest, res: VercelResponse) {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method not allowed' });
  }

  try {
    const { prompt, imageBase64, mimeType, clientKey, resolution } = req.body;

    if (!clientKey) {
      return res.status(401).json({ error: 'Client key is required' });
    }

    // 1. Check User in DB
    const { rows } = await sql`SELECT * FROM users WHERE client_api_key = ${clientKey} LIMIT 1`;

    if (rows.length === 0) {
      return res.status(403).json({ error: 'Invalid Client Key' });
    }

    const user = rows[0];

    // 2. Check and Reset Daily Limit
    const now = new Date();
    const today = now.toISOString().split('T')[0]; // YYYY-MM-DD
    const lastReset = user.last_reset_date ? new Date(user.last_reset_date).toISOString().split('T')[0] : null;

    let currentUsage = user.usage_count;

    if (lastReset !== today) {
      await sql`UPDATE users SET usage_count = 0, last_reset_date = ${today} WHERE id = ${user.id}`;
      currentUsage = 0;
    }

    // 3. Enforce Limit
    if (currentUsage >= user.daily_limit) {
      return res.status(429).json({ 
        error: `Daily limit of ${user.daily_limit} reached. Please wait until tomorrow.` 
      });
    }

    // 4. Call Gemini AI
    const model = 'gemini-3-pro-image-preview'; 

    const response = await ai.models.generateContent({
        model: model,
        contents: {
            parts: [
                { inlineData: { data: imageBase64, mimeType: mimeType } },
                { text: prompt },
            ],
        },
        config: {
            imageConfig: { imageSize: resolution || '4K' },
        },
    });

    // 5. Extract Image
    let resultImage = null;
    let resultMime = null;

    if (response.candidates?.[0]?.content?.parts) {
        for (const part of response.candidates[0].content.parts) {
            if (part.inlineData) {
                resultImage = part.inlineData.data;
                resultMime = part.inlineData.mimeType;
                break;
            }
        }
    }

    if (!resultImage) {
        throw new Error("Model did not return an image.");
    }

    // 6. Increment Usage
    await sql`UPDATE users SET usage_count = usage_count + 1 WHERE id = ${user.id}`;

    return res.status(200).json({ 
      data: resultImage, 
      mimeType: resultMime,
      remaining: user.daily_limit - (currentUsage + 1)
    });

  } catch (error: any) {
    console.error("AI Gen Error:", error);
    return res.status(500).json({ error: error.message || "Internal Server Error" });
  }
}
```

