    const byteArray = new Uint8Array(byteNumbers);
    const blob = new Blob([byteArray], { type: mimeType });
    const newImageUrl = URL.createObjectURL(blob);

    // 2. Create new AlbumImage
    const newImage: AlbumImage = {
        id: `ai-img-${Date.now()}`,
        url: newImageUrl,
        used: 1,
