    };

    // 3. Add to library and update old image usage
    setLibraryImages(prev => {
        const updatedImages = prev.map(img => {
            if (img.id === originalImageId) {
                return { ...img, used: Math.max(0, (img.used || 0) - 1) };
            }
            return img;
