  const renderAiToolbar = () => (
    <div className="flex items-center justify-between gap-1 w-full">
        <button 
            onClick={() => setEditMode('transform')} 
            title={t('back')}
            className="p-2 text-white bg-gray-700/50 rounded-md hover:bg-gray-600/50"
