                <button onClick={handleEnterEditMode} className="p-1 text-white hover:bg-white/30 rounded" title={t('editPhoto')}>
                    <PencilIcon className="w-4 h-4" />
                </button>
                <button onClick={handleDownload} className="p-1 text-white hover:bg-white/30 rounded" title={t('downloadImage')}>
                    <DownloadIcon className="w-4 h-4" />
                </button>
                <button onClick={onRemove} className="p-1 text-white hover:bg-red-500/80 rounded" title={t('removeImageTitle')}>
                    <XMarkIcon className="w-4 h-4" />
                </button>
            </div>
          )}

          {isEditing && (
            <div 
                data-hide-on-capture="true"
                className="absolute bottom-0 left-0 right-0 bg-black/60 backdrop-blur-sm p-2 z-20"
                onClick={(e) => e.stopPropagation()}
                onMouseDown={(e) => e.stopPropagation()}
                onTouchStart={(e) => e.stopPropagation()}
            >
              {editMode === 'transform' ? (
                  isMobile ? renderMobileToolbar() : renderDesktopToolbar()
              ) : (
                  renderAiToolbar()
              )}
            </div>
          )}
        </div>
    </>
  );
};

export default PlacedImage;

The error `Unexpected token 'R', "Request En"...` is happening because the image you are sending to the server is too large. Vercel Serverless Functions have a payload limit (usually 4.5MB), and raw 4K images often exceed this, causing the server to return a raw text error "Request Entity Too Large" instead of JSON.

To fix this, I will:
1.  **Update `utils.ts`**: Add a helper function to resize and compress the image on the client side before sending it to the API.
2.  **Update `components/PlacedImage.tsx`**: Use this compression function to ensure the payload stays within limits, and improve error handling to catch non-JSON responses gracefully.

